// Parse perception_tick response. The Python orchestrator returns:
//   {
//     "exit_status": "completed" | "killed_by_budget_gate",
//     "counts": { pubmed: {...}, ctgov: {...}, ... },
//     "total_new_rows": N,
//     "duration_seconds": N
//   }
const r = $input.first().json;
const exit_status = r.exit_status || 'unknown';
const total = r.total_new_rows ?? 0;
const dt = r.duration_seconds ?? 0;
const counts = r.counts || {};
const g = (step, key) => parseInt((counts[step] || {})[key] || 0);
const pubmed = g('pubmed', 'ledger_inserted');
const ctgov = g('ctgov', 'ledger_inserted');
const preprints = g('preprints', 'ledger_inserted');
const gap = g('gap_filler', 'ledger_inserted');
const neg = g('negative', 'ledger_inserted');
const summary = `\u{1F578}\uFE0F perception_tick ${exit_status} +${total} rows in ${dt}s\n  pubmed=${pubmed} ctgov=${ctgov} preprints=${preprints}\n  gap-fill=${gap} negative=${neg}`;
return [{ json: { summary, exit_status, total, ...r } }];
